#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N % 2 == 1) {
            printf("-1\n");
            continue;
        }
        int half = N / 2;
        char *s = (char*)malloc(N + 1);
        for (int i = 0; i < half; ++i) s[i] = '0';
        for (int i = half; i < N; ++i) s[i] = '1';
        s[N] = '\0';
        printf("%s\n", s);
        free(s);
    }
    return 0;
}

