#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        if n % 2 == 1:
            out_lines.append('-1')
        else:
            half = n // 2
            out_lines.append('0'*half + '1'*half)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

